import React, { useState, useEffect } from "react";
import { Dialog, CircularProgress, Button, Backdrop } from "@mui/material";
import toast, { Toaster } from "react-hot-toast";
import {
  clearErrors,
  updateProdImg,
} from "../../../redux/actions/admin/adminProductAction";
import { useDispatch, useSelector } from "react-redux";

const UpdateProdImage = ({
  openUpdateImgDial,
  setOpenUpdateImgDial,
  photo,
  upImageId,
}) => {
  const dispatch = useDispatch();
  const [base64Data, setBase64Data] = useState(null);
  const [selectedFileName, setselectedFileName] = useState("");

//   updateProdImg
  const updateProdImgState = useSelector((state) => state.updateProdImg);
  const { updateImgLoading, updateImgSuccess, updateImgError } = updateProdImgState;


  //convert the image into base64
  const onChange = (e) => {
    let file = e.target.files[0];
    setselectedFileName(e.target.files[0].name);
    const fileSizeLimit = 512000;
    if (file.size > fileSizeLimit) {
      alert("File size exceeds limit of 500 KB");
      return;
    }

    if (file) {
      const reader = new FileReader();
      reader.onload = _handleReaderLoaded.bind(e);
      reader.readAsBinaryString(file);
    }
  };

  const _handleReaderLoaded = (e) => {
    let binaryString = e.target.result;
    setBase64Data(btoa(binaryString));
  };

  const updateImage = () => {
    if (!base64Data) {
      return toast.error("All are required", {
        position: "top-center",
        duration: 3000,
      });
    }
    dispatch(updateProdImg(upImageId, base64Data));
  };

   const resetHandler = () => {
    setBase64Data("");
    setselectedFileName("")
  };
  useEffect(() => {
    if (updateImgError) {
      toast.error("Something went wrong", {
        position: "top-center",
        duration: 3000,
      });
      dispatch(clearErrors());
    }
    if (updateImgSuccess) {
      setOpenUpdateImgDial(false);
      toast.success("Image Updated Successfully", {
        position: "top-center",
        duration: 3000,
      });
      dispatch({ type: "UPDATE_PRODIMG_RESET" });
      resetHandler();
    }
  }, [dispatch, setOpenUpdateImgDial, updateImgError, updateImgSuccess]);

  return (
    <>
      <Dialog
        open={openUpdateImgDial}
        onClose={() => setOpenUpdateImgDial(false)}
      >
        <div
          style={{
            margin: "1rem",
          }}
        >
          {updateImgLoading ? (
            <>
              <Backdrop
                sx={{
                  color: "#fff",
                  zIndex: (theme) => theme.zIndex.drawer + 1,
                }}
                open={updateImgLoading}
              >
                <CircularProgress color="inherit" />
              </Backdrop>
            </>
          ) : null}
          <div
            style={{
              display: "flex",
              justifyContent: "center",
            }}
          >
            <img
              src={photo}
              alt="Product"
              style={{
                width: "100%",
                height: "100%",
                borderRadius: "8px",
              }}
            />
          </div>
          <br />

          {/* image */}
          <div
            className="fileUpoption"
            style={{
              marginTop: "10px",
            }}
          >
            <input
              type="file"
              name="image"
              id="file"
              accept=".jpg, .jpeg, .png"
              onChange={(e) => onChange(e)}
            />
            <label htmlFor="file">{selectedFileName}</label>
            <br />
            <div
              style={{
                display: "flex",
                marginTop: "5px",
              }}
            ></div>
          </div>

          <Button
            onClick={() => updateImage()}
            sx={{
              display: "flex",
              justifyContent: "center",
              marginRight: "auto",
              marginLeft: "auto",
              marginTop: "1rem",
            }}
            variant="contained"
            //   onClick={openPrimaryCategoryDialog}
            //   endIcon={<AddIcon />}
          >
            Update Image
          </Button>
        </div>
      </Dialog>
      <Toaster />
    </>
  );
};

export default UpdateProdImage;
